def decimal_hours_to_duration(value):
    if value is None:
        return None
    minutes = int(round(float(value) * 60))
    return timedelta(minutes=minutes)


def duration_to_decimal_hours(value):
    if value is None:
        return None
    return round(value.total_seconds() / 3600, 2)


