def copy_legacy_weather_and_uppercase_obras(apps, schema_editor):
    Obra = apps.get_model('rdo', 'Obra')
    RDO = apps.get_model('rdo', 'RDO')
    for obra in Obra.objects.all().iterator():
        nome = (obra.nome or '').upper()
